module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

localparam S0 = 1'b0, S1 = 1'b1;

reg state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= S0;
        data_out <= 1'b0;
    end
    else begin
        case (state)
            S0: begin
                if (data_in) begin
                    state <= S1;
                end
                else begin
                    state <= S0;
                end
                data_out <= 1'b0;
            end
            S1: begin
                if (data_in) begin
                    state <= S0;
                end
                else begin
                    state <= S0;
                end
                data_out <= 1'b0;
            end
            default: begin
                state <= S0;
                data_out <= 1'b0;
            end
        endcase
    end
end

endmodule
